        get() {
            return if (Build.VERSION.SDK_INT < 29) {
                val dir =
                    Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOCUMENTS).absolutePath
                val path = dir + File.separator + CommUtils.getAppName() + "/house"
                val file = File(path)
                if (!file.exists()) {
                    file.mkdirs()
