import com.elvishew.xlog.XLog

class DegradeServiceImpl {
    fun init(context: Context?) {
    }

    fun onLost(
        context: Context?,
        path: String?,
    ) {
        if (context != null) {
            Toast.makeText(context, "Navigation failed: $path", Toast.LENGTH_SHORT).show()
            XLog.e("Navigation failed to path: $path")
        }
    }
