object Logger {
    @JvmStatic
    fun e(clazz: Class<*>, msg: String) {
        if (BuildConfig.DEBUG) {
            Log.e(clazz.simpleName, msg + "")
        }
    }

    @JvmStatic
    fun e(tag: String?, msg: String) {
