        val str =
            if (SharedManager.getTemperature() == 1) {
                "($min~$maxÂ°C)"
            } else {
                val maxT: Int = (max * 1.8000 + 32.00).toInt()
                val minT: Int = (min * 1.8000 + 32.00).toInt()
                "($minT~$maxTÂ°F)"
            }
        return str
    }

    @JvmStatic
    fun showUnit(): String {
        val str =
            if (SharedManager.getTemperature() == 1) {
                "Â°C"
            } else {
                "Â°F"
            }
        return str
    }

    @JvmStatic
    fun showUnitValue(value: Float): Float {
        val str =
            if (SharedManager.getTemperature() == 1) {
