        return if (videoPath.uppercase().endsWith(".MP4") || videoPath.uppercase()
                .endsWith(".AVI")
        ) {
            try {
                val mmr = MediaMetadataRetriever()
                mmr.setDataSource(videoPath)
                mmr.extractMetadata(MediaMetadataRetriever.METADATA_KEY_DURATION)!!.toLong()
            } catch (e: Exception) {
                0
            }
        } else {
            0
        }
    }
}


