            }

            MotionEvent.ACTION_MOVE -> {
                trackTouchEvent(event)
            }

            MotionEvent.ACTION_UP -> {
                isPressed = false
                trackTouchEvent(event)
                invalidate()
                onSeekBarChangeListener?.onStopTrackingTouch(this)
            }

            MotionEvent.ACTION_CANCEL -> {
                isPressed = false
